module decrementer (
  input clk,
  input en,
  input rst,
  output reg [9:0] count);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin
    if (rst)
        count <= 10'b1111111111;
    else if (en)
        count <= count - 1;
end
endmodule
